package main

import (
    "crypto/rsa"
    "github.com/golang-jwt/jwt/v5"
)

// Compliant: Using strong RSA algorithm
privateKey, _ := rsa.GenerateKey(rand.Reader, 2048)
token := jwt.NewWithClaims(jwt.SigningMethodRS256, claims)
tokenString, _ := token.SignedString(privateKey)

// Compliant: Strong HMAC key (32+ bytes)
strongKey := []byte("your-256-bit-secret-key-here-32-chars")
token := jwt.NewWithClaims(jwt.SigningMethodHS256, claims)
tokenString, _ := token.SignedString(strongKey)

// Compliant: Proper signature verification with algorithm validation
token, err := jwt.Parse(tokenString, func(token *jwt.Token) (interface{}, error) {
    // Validate the algorithm
    if _, ok := token.Method.(*jwt.SigningMethodRSA); !ok {
        return nil, fmt.Errorf("unexpected signing method: %v", token.Header["alg"])
    }
    return publicKey, nil
})

if err != nil || !token.Valid {
    return errors.New("invalid token")
}
